function isOwnedByViewer(canisterId: string): boolean {
  const automaton = mockAutomatons.find((entry) => entry.canisterId === canisterId);

  if (automaton === undefined) {
    return false;
  }

  return (
    automaton.steward.address.toLowerCase() ===
    SIMULATED_VIEWER_ADDRESS.toLowerCase()
  );
}

