import { useEffect, useState } from "react";

import type { AutomatonDetail } from "../../../../../packages/shared/src/automaton.js";

type CommandEntry =
  | {
      kind: "system" | "response";
      text: string;
    }
  | {
      kind: "command";
      text: string;
    };

function buildInitialEntries(
  automaton: AutomatonDetail | null,
  canExecute: boolean
): CommandEntry[] {
  if (automaton === null) {
    return [
      {
        kind: "system",
        text: "Select an automaton from the grid to open the signed command shell."
      }
    ];
  }

  if (!canExecute) {
    return [
      {
        kind: "system",
        text: `Connected in read-only mode to ${automaton.name}.`
      },
      {
        kind: "response",
        text: "Connect steward wallet to execute commands."
      }
    ];
  }

  return [
    {
      kind: "system",
      text: `Connected to ${automaton.name}. Type "help" for commands.`
    }
  ];
}

function buildCommandResponse(
  command: string,
  automaton: AutomatonDetail
): string {
  const [name] = command.split(/\s+/, 1);
  const normalized = name.toLowerCase();

  switch (normalized) {
    case "help":
      return "Available commands: help, status, balance, strategies, skills, constitution, logs, heartbeat, shutdown";
    case "status":
      return `State: ${automaton.runtime.agentState} | Tier: ${automaton.tier} | Loop: ${automaton.runtime.loopEnabled ? "enabled" : "disabled"}`;
    case "balance":
      return `ETH: ${automaton.financials.netWorthEth ?? "0"} | USD: ${automaton.financials.netWorthUsd ?? "0"} | Cycles: ${automaton.financials.cyclesBalance.toLocaleString("en-US")}`;
    case "strategies":
      return automaton.strategies
        .map((entry) => `${entry.key.primitive}@${entry.key.protocol} [${entry.status}]`)
        .join(", ");
    case "skills":
      return automaton.skills
        .map((entry) => `${entry.name}: ${entry.enabled ? "enabled" : "disabled"}`)
        .join(", ");
    case "constitution":
      return automaton.promptLayers.join(" | ");
    case "logs":
      return automaton.monologue
        .slice(-2)
        .map((entry) => entry.message)
        .join(" / ");
    case "heartbeat":
      return `Interval: ${automaton.runtime.heartbeatIntervalSeconds ?? "n/a"}s | Last transition: ${new Date(automaton.runtime.lastTransitionAt).toISOString()}`;
    case "shutdown":
      return "Preview mode only: shutdown is not executed in the local shell.";
    default:
      return `Unknown command: "${command}". Type "help" for available commands.`;
  }
}

interface CommandLinePanelProps {
  automaton: AutomatonDetail | null;
  canExecute: boolean;
}

export function CommandLinePanel({
  automaton,
  canExecute
}: CommandLinePanelProps) {
  const [command, setCommand] = useState("");
  const [entries, setEntries] = useState<CommandEntry[]>(
    buildInitialEntries(automaton, canExecute)
  );

  useEffect(() => {
    setEntries(buildInitialEntries(automaton, canExecute));
    setCommand("");
  }, [automaton, canExecute]);

  function submitCommand() {
    if (automaton === null || !canExecute) {
      return;
    }

    const trimmed = command.trim();

    if (trimmed.length === 0) {
      return;
    }

    setEntries((previous) => [
      ...previous,
      {
        kind: "command",
        text: trimmed
      },
      {
        kind: "response",
        text: buildCommandResponse(trimmed, automaton)
      }
    ]);
    setCommand("");
  }

  return (
    <section className="cli-section" aria-labelledby="command-line-heading">
      <div className="panel-heading">
        <h3 id="command-line-heading">Command Line</h3>
        <span className="panel-note">
          {automaton === null
            ? "Signed steward plane"
            : canExecute
              ? "Steward wallet matched"
              : "Read-only fallback"}
        </span>
      </div>

      <div className="cli-output" role="log">
        {entries.map((entry, index) => (
          <div className={`cli-line is-${entry.kind}`} key={`${entry.text}-${index}`}>
            {entry.kind === "command" ? (
              <>
                <span className="cli-prompt">&gt;</span> {entry.text}
              </>
            ) : (
              entry.text
            )}
          </div>
        ))}
      </div>

      {canExecute && automaton !== null ? (
        <div className="cli-input-row">
          <span className="cli-prompt-label">&gt;</span>
          <input
            aria-label="Command input"
            className="cli-input"
            onChange={(event) => {
              setCommand(event.target.value);
            }}
            onKeyDown={(event) => {
              if (event.key === "Enter") {
                submitCommand();
              }
            }}
            placeholder="enter command..."
            type="text"
            value={command}
          />
          <button className="cli-send" onClick={submitCommand} type="button">
            Send
          </button>
        </div>
      ) : (
        <p className="cli-readonly">
          {automaton === null
            ? "Signed responses will render here after an automaton is selected."
            : "Connect steward wallet to execute commands."}
        </p>
      )}
    </section>
  );
}

import { useEffect, useState } from "react";

import { fetchOpenRouterModels } from "../../api/openrouter";
import {
  defaultModelOptions,
  type ProviderModelOption
} from "../../lib/default-models";
import {
  buildProviderSummary,
  chainOptions,
  createInitialSpawnWizardState,
  describeFundingValidation,
  getActiveChainLabel,
  getFundingPreview,
  getRiskProfile,
  skillCatalog,
  strategyCatalog,
  toggleSelection,
  TOTAL_SPAWN_STEPS,
  type SpawnWizardState
} from "./spawn-state";
import { ChainStep } from "./steps/ChainStep";
import { FundStep } from "./steps/FundStep";
import { ProviderConfigStep } from "./steps/ProviderConfigStep";
import { RiskStep } from "./steps/RiskStep";
import { SkillsStep } from "./steps/SkillsStep";
import { StrategiesStep } from "./steps/StrategiesStep";

interface SpawnWizardProps {
  isOpen: boolean;
  onClose: () => void;
}

const stepTitles = [
  "Select chain",
  "Risk appetite",
  "Strategies",
  "Skills",
  "Provider config",
  "Fund"
] as const;

export function SpawnWizard({ isOpen, onClose }: SpawnWizardProps) {
  const [stepIndex, setStepIndex] = useState(0);
  const [state, setState] = useState<SpawnWizardState>(
    createInitialSpawnWizardState()
  );
  const [modelOptions, setModelOptions] =
    useState<ProviderModelOption[]>(defaultModelOptions);
  const [isLoadingModels, setIsLoadingModels] = useState(false);
  const [modelStatusMessage, setModelStatusMessage] = useState(
    "Using curated fallback models until the live catalog is requested."
  );

  useEffect(() => {
    if (!isOpen) {
      return;
    }

    const controller = new AbortController();

    setIsLoadingModels(true);
    setModelStatusMessage("Loading live OpenRouter models.");

    void fetchOpenRouterModels(controller.signal)
      .then((models) => {
        setModelOptions(models);
        setModelStatusMessage("Loaded live OpenRouter models.");
      })
      .catch(() => {
        setModelOptions(defaultModelOptions);
        setModelStatusMessage(
          "OpenRouter catalog unavailable, using curated fallback models."
        );
      })
      .finally(() => {
        setIsLoadingModels(false);
      });

    return () => {
      controller.abort();
    };
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) {
      return;
    }

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        onClose();
      }
    };

    window.addEventListener("keydown", handleKeyDown);

    return () => {
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [isOpen, onClose]);

  const fundingPreview = getFundingPreview(state);
  const validationMessage = describeFundingValidation(fundingPreview);
  const canSubmit =
    state.chain === "base" &&
    fundingPreview.minimumMet &&
    fundingPreview.grossAmount > 0;

  function resetWizard() {
    setStepIndex(0);
    setState(createInitialSpawnWizardState());
    setModelOptions(defaultModelOptions);
    setModelStatusMessage(
      "Using curated fallback models until the live catalog is requested."
    );
    setIsLoadingModels(false);
  }

  function closeWizard() {
    resetWizard();
    onClose();
  }

  function advanceStep() {
    setStepIndex((current) =>
      current < TOTAL_SPAWN_STEPS - 1 ? current + 1 : current
    );
  }

  function retreatStep() {
    setStepIndex((current) => (current > 0 ? current - 1 : current));
  }

  function handleSubmit() {
    if (!canSubmit) {
      return;
    }

    closeWizard();
  }

  return (
    <div
      aria-hidden={!isOpen}
      className={`spawn-overlay${isOpen ? " is-open" : ""}`}
      onClick={(event) => {
        if (event.target === event.currentTarget) {
          closeWizard();
        }
      }}
    >
      <section
        aria-label="Spawn automaton wizard"
        aria-modal="true"
        className="spawn-wizard"
        role="dialog"
      >
        <button
          aria-label="Close spawn wizard"
          className="spawn-close"
          onClick={closeWizard}
          type="button"
        >
          X
        </button>

        <header className="spawn-header">
          <div>
            <p className="section-label">Spawn wizard</p>
            <h2 className="spawn-heading">Spawn Automaton</h2>
          </div>
          <div className="spawn-header-meta">
            <span>
              Step {stepIndex + 1} of {TOTAL_SPAWN_STEPS}
            </span>
            <strong>{stepTitles[stepIndex]}</strong>
          </div>
        </header>

        <div className="spawn-progress">
          <div
            className="spawn-progress-fill"
            style={{
              width: `${((stepIndex + 1) / TOTAL_SPAWN_STEPS) * 100}%`
            }}
          />
        </div>

        <div className="spawn-body">
          {stepIndex === 0 ? (
            <ChainStep
              onChange={(chain) => {
                setState((current) => ({
                  ...current,
                  chain
                }));
              }}
              value={state.chain}
            />
          ) : null}

          {stepIndex === 1 ? (
            <RiskStep
              onChange={(risk) => {
                setState((current) => ({
                  ...current,
                  risk
                }));
              }}
              value={state.risk}
            />
          ) : null}

          {stepIndex === 2 ? (
            <StrategiesStep
              catalog={strategyCatalog}
              onToggle={(id) => {
                setState((current) => ({
                  ...current,
                  strategies: toggleSelection(current.strategies, id)
                }));
              }}
              selectedIds={state.strategies}
            />
          ) : null}

          {stepIndex === 3 ? (
            <SkillsStep
              catalog={skillCatalog}
              onToggle={(id) => {
                setState((current) => ({
                  ...current,
                  skills: toggleSelection(current.skills, id)
                }));
              }}
              selectedIds={state.skills}
            />
          ) : null}

          {stepIndex === 4 ? (
            <ProviderConfigStep
              braveSearchApiKey={state.braveSearchApiKey}
              customModelId={state.customModelId}
              isLoadingModels={isLoadingModels}
              modelOptions={modelOptions}
              modelStatusMessage={modelStatusMessage}
              onBraveSearchApiKeyChange={(value) => {
                setState((current) => ({
                  ...current,
