export function createInitialSpawnWizardState(): SpawnWizardState {
  return {
    chain: "base",
    risk: 3,
    strategies: ["yield-farming", "cycle-management"],
    skills: ["spawn-children"],
    openRouterApiKey: "",
    selectedModelId: "",
    customModelId: "",
    braveSearchApiKey: "",
    asset: "usdc",
    grossAmountInput: "100"
  };
}

export function getRiskProfile(value: RiskProfile["value"]): RiskProfile {
  return riskProfiles.find((profile) => profile.value === value) ?? riskProfiles[2];
}

export function getActiveChainLabel(chain: SpawnChain): string {
  return chainOptions.find((entry) => entry.id === chain)?.label ?? chain;
}

export function toggleSelection(
  values: string[],
  candidate: string
): string[] {
  return values.includes(candidate)
    ? values.filter((value) => value !== candidate)
    : [...values, candidate];
}

function parseGrossAmount(rawValue: string): number {
  const parsed = Number(rawValue);

  return Number.isFinite(parsed) && parsed > 0 ? parsed : 0;
}

function assetToUsd(asset: SpawnAsset, amount: number): number {
  return asset === "eth" ? amount * MOCK_ETH_USD_RATE : amount;
}

function usdToAsset(asset: SpawnAsset, amountUsd: number): number {
  return asset === "eth" ? amountUsd / MOCK_ETH_USD_RATE : amountUsd;
}

function formatUsd(value: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  }).format(value);
}

function formatAsset(asset: SpawnAsset, amount: number): string {
  return `${new Intl.NumberFormat("en-US", {
    minimumFractionDigits: asset === "eth" ? 4 : 2,
    maximumFractionDigits: asset === "eth" ? 4 : 2
  }).format(amount)} ${asset.toUpperCase()}`;
}

export function getFundingPreview(state: SpawnWizardState): FundingPreview {
  const grossAmount = parseGrossAmount(state.grossAmountInput);
  const grossUsd = assetToUsd(state.asset, grossAmount);
  const platformFeeAmount = usdToAsset(state.asset, MOCK_PLATFORM_FEE_USD);
  const creationCostAmount = usdToAsset(state.asset, MOCK_CREATION_COST_USD);
  const netForwardAmount = Math.max(
    0,
    grossAmount - platformFeeAmount - creationCostAmount
  );
  const netForwardUsd = Math.max(
    0,
    grossUsd - MOCK_PLATFORM_FEE_USD - MOCK_CREATION_COST_USD
  );

  return {
    grossAmount,
    grossUsd,
    minimumUsd: MINIMUM_GROSS_PAYMENT_USD,
    minimumMet: grossUsd >= MINIMUM_GROSS_PAYMENT_USD,
    platformFeeUsd: MOCK_PLATFORM_FEE_USD,
    creationCostUsd: MOCK_CREATION_COST_USD,
    netForwardUsd,
    grossDisplay: formatAsset(state.asset, grossAmount),
    platformFeeDisplay: formatAsset(state.asset, platformFeeAmount),
    creationCostDisplay: formatAsset(state.asset, creationCostAmount),
    netForwardDisplay: formatAsset(state.asset, netForwardAmount)
  };
}

export function getSelectedModel(state: SpawnWizardState): string | null {
  const trimmedCustomModel = state.customModelId.trim();

  if (trimmedCustomModel !== "") {
    return trimmedCustomModel;
  }

  return state.selectedModelId.trim() === "" ? null : state.selectedModelId.trim();
}

export function buildProviderSummary(state: SpawnWizardState): string {
  const model = getSelectedModel(state);

  if (model === null) {
    return "Inference disabled until steward config";
  }

  return model;
}

export function describeFundingValidation(preview: FundingPreview): string {
  if (preview.minimumMet) {
    return `Gross payment clears the ${formatUsd(preview.minimumUsd)} minimum.`;
  }

  return `Gross payment must be at least ${formatUsd(preview.minimumUsd)} before fees.`;
}

export function formatUsdValue(value: number): string {
  return formatUsd(value);
}

import type {
  AutomatonRecord,
  MonologueEntry
} from "./automaton.js";
import type {
  SessionAuditEntry,
  SpawnSession
} from "./spawn.js";

export const AUTOMATON_EVENT_TYPES = [
  "spawn",
  "update",
  "action",
  "message",
  "monologue",
  "offline"
] as const;

export const SPAWN_EVENT_TYPES = [
  "spawn.session.updated",
  "spawn.session.completed",
  "spawn.session.failed",
  "spawn.session.expired"
] as const;

export type AutomatonEventType = (typeof AUTOMATON_EVENT_TYPES)[number];
export type SpawnEventType = (typeof SPAWN_EVENT_TYPES)[number];

export interface AutomatonSpawnEvent {
  type: "spawn";
  automaton: AutomatonRecord;
}

export interface AutomatonUpdateEvent {
  type: "update";
  canisterId: string;
  changes: Partial<AutomatonRecord>;
  timestamp: number;
}

export interface AutomatonActionEvent {
  type: "action";
  canisterId: string;
  action: string;
  turnId: string | null;
  timestamp: number;
}

export interface AutomatonMessageEvent {
  type: "message";
  fromCanisterId: string;
  toCanisterId: string;
  timestamp: number;
}

export interface AutomatonMonologueEvent {
  type: "monologue";
  canisterId: string;
  entry: MonologueEntry;
}

export interface AutomatonOfflineEvent {
  type: "offline";
  canisterId: string;
  timestamp: number;
}

export interface SpawnSessionUpdatedEvent {
  type: "spawn.session.updated";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export interface SpawnSessionCompletedEvent {
  type: "spawn.session.completed";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export interface SpawnSessionFailedEvent {
  type: "spawn.session.failed";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export interface SpawnSessionExpiredEvent {
  type: "spawn.session.expired";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export type RealtimeEvent =
  | AutomatonSpawnEvent
  | AutomatonUpdateEvent
  | AutomatonActionEvent
  | AutomatonMessageEvent
  | AutomatonMonologueEvent
  | AutomatonOfflineEvent
  | SpawnSessionUpdatedEvent
  | SpawnSessionCompletedEvent
  | SpawnSessionFailedEvent
  | SpawnSessionExpiredEvent;

import type {
  SpawnEventType,
  SpawnSessionDetail,
  SpawnedAutomatonRecord
} from "@ic-automaton/shared";
import type { FastifyInstance, FastifyPluginAsync } from "fastify";

function normalizeLimit(value: unknown) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return 50;
  }

  return Math.min(Math.floor(parsed), 100);
}

function normalizeCursor(value: unknown) {
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : undefined;
}

function selectSpawnSessionEventType(detail: SpawnSessionDetail): SpawnEventType {
  switch (detail.session.state) {
    case "complete":
      return "spawn.session.completed";
    case "failed":
      return "spawn.session.failed";
    case "expired":
      return "spawn.session.expired";
    default:
      return "spawn.session.updated";
  }
}

function shouldBroadcastSpawnSessionUpdate(
  previous: SpawnSessionDetail | null,
  next: SpawnSessionDetail
) {
  if (!previous) {
    return true;
  }

  return (
    previous.session.updatedAt !== next.session.updatedAt ||
    previous.session.state !== next.session.state ||
    previous.session.paymentStatus !== next.session.paymentStatus ||
    previous.audit.length !== next.audit.length ||
    previous.registryRecord?.canisterId !== next.registryRecord?.canisterId ||
    previous.escrow?.updatedAt !== next.escrow?.updatedAt ||
    previous.escrow?.paymentStatus !== next.escrow?.paymentStatus
  );
}

async function resolveSpawnSessionDetail(
  fastify: FastifyInstance,
  sessionId: string
): Promise<SpawnSessionDetail | null> {
  const cached = await fastify.indexerStore.getSpawnSessionDetail(sessionId);
  const factorySnapshot = await fastify.factoryClient.getSpawnSession(sessionId);

  if (!factorySnapshot) {
    return cached;
  }

  const escrow = await fastify.escrowClient.getEscrowPayment(
    sessionId,
    factorySnapshot.session.quoteTermsHash
  );
  const detail: SpawnSessionDetail = {
    session: factorySnapshot.session,
    audit: factorySnapshot.audit,
    escrow: escrow ?? cached?.escrow ?? null,
    registryRecord: factorySnapshot.registryRecord ?? cached?.registryRecord ?? null
  };

  await fastify.indexerStore.upsertSpawnSession(detail);
  if (shouldBroadcastSpawnSessionUpdate(cached, detail)) {
    fastify.realtimeHub.broadcast({
      type: selectSpawnSessionEventType(detail),
      session: detail.session,
      audit: detail.audit
    });
  }

  return detail;
}

async function resolveRegistryRecord(
  fastify: FastifyInstance,
  canisterId: string
): Promise<SpawnedAutomatonRecord | null> {
  if (fastify.factoryClient.isConfigured()) {
    const record = await fastify.factoryClient.getSpawnedAutomaton(canisterId);
    if (record) {
      await fastify.indexerStore.upsertSpawnedAutomatonRegistry([record]);
      return record;
    }
  }

  return fastify.indexerStore.getSpawnedAutomatonRegistryRecord(canisterId);
}

export const spawnSessionRoutes: FastifyPluginAsync = async (fastify) => {
  fastify.get("/api/spawn-sessions/:sessionId", async (request, reply) => {
    const params = request.params as { sessionId: string };
    const detail = await resolveSpawnSessionDetail(fastify, params.sessionId);

    if (!detail) {
      reply.code(404);
      return {
        ok: false,
        error: "Spawn session not found",
        sessionId: params.sessionId
      };
    }

    return detail;
  });

  fastify.get("/api/spawned-automatons", async (request) => {
    const query = request.query as {
      cursor?: string;
      limit?: string;
    };
    const cursor = normalizeCursor(query.cursor);
    const limit = normalizeLimit(query.limit);

    if (fastify.factoryClient.isConfigured()) {
      const page = await fastify.factoryClient.listSpawnedAutomatons(cursor, limit);
      await fastify.indexerStore.upsertSpawnedAutomatonRegistry(page.items);
      return page;
    }

    return fastify.indexerStore.listSpawnedAutomatonRegistry({
      cursor,
      limit
    });
  });

  fastify.get("/api/spawned-automatons/:canisterId", async (request, reply) => {
    const params = request.params as { canisterId: string };
    const record = await resolveRegistryRecord(fastify, params.canisterId);

    if (!record) {
      reply.code(404);
      return {
        ok: false,
        error: "Spawned automaton registry record not found",
        canisterId: params.canisterId
