import type { FastifyPluginAsync } from "fastify";

import type { AutomatonTier, ChainSlug } from "@ic-automaton/shared";

function normalizeLimit(value: unknown) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return 50;
  }

  return Math.min(Math.floor(parsed), 100);
}

function normalizeCursor(value: unknown) {
  if (value === undefined) {
    return undefined;
  }

  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : undefined;
}

function normalizeString(value: unknown) {
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : undefined;
}

export const automatonRoutes: FastifyPluginAsync = async (fastify) => {
  fastify.get("/api/automatons", async (request) => {
    const query = request.query as {
      steward?: string;
      chain?: ChainSlug;
      tier?: AutomatonTier;
    };

    return fastify.indexerStore.listAutomatons({
      steward: normalizeString(query.steward),
      chain: normalizeString(query.chain) as ChainSlug | undefined,
      tier: normalizeString(query.tier) as AutomatonTier | undefined
    });
  });

  fastify.get("/api/automatons/:canisterId", async (request, reply) => {
    const params = request.params as { canisterId: string };
    const automaton = await fastify.indexerStore.getAutomatonDetail(params.canisterId);

    if (!automaton) {
      reply.code(404);
      return {
        ok: false,
        error: "Automaton not found",
        canisterId: params.canisterId
      };
    }

    return automaton;
  });

  fastify.get("/api/automatons/:canisterId/monologue", async (request) => {
    const params = request.params as { canisterId: string };
    const query = request.query as {
      before?: string;
      limit?: string;
    };

    return fastify.indexerStore.listMonologue(params.canisterId, {
      before: normalizeCursor(query.before),
      limit: normalizeLimit(query.limit)
    });
  });
};

import websocket from "@fastify/websocket";
import Fastify, { type FastifyBaseLogger, type FastifyInstance } from "fastify";
import { fileURLToPath } from "node:url";

import { resolveIndexerConfig, type IndexerConfigOverrides } from "./config.js";
import { EscrowClient } from "./integrations/escrow-client.js";
import { FactoryClient } from "./integrations/factory-client.js";
import { automatonRoutes } from "./routes/automatons.js";
import { healthRoutes } from "./routes/health.js";
import { realtimeRoutes } from "./routes/realtime.js";
import { spawnSessionRoutes } from "./routes/spawn-sessions.js";
import { createSqliteStore, type IndexerStore } from "./store/sqlite.js";
import "./types.js";
import { RealtimeHub } from "./ws/events.js";

export interface BuildServerOptions {
  config?: IndexerConfigOverrides;
  escrowClient?: EscrowClient;
  factoryClient?: FactoryClient;
  logger?: boolean | FastifyBaseLogger;
  store?: IndexerStore;
  realtimeHub?: RealtimeHub;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const config = resolveIndexerConfig(process.env, options.config);
  const store =
    options.store ??
    createSqliteStore({
      databasePath: config.databasePath
    });
  const factoryClient = options.factoryClient ?? new FactoryClient();
  const escrowClient = options.escrowClient ?? new EscrowClient();
  const realtimeHub = options.realtimeHub ?? new RealtimeHub(config.websocketPath);

  const app = Fastify({
    logger: options.logger ?? false
  });

  app.decorate("escrowClient", escrowClient);
  app.decorate("factoryClient", factoryClient);
  app.decorate("startedAt", Date.now());
  app.decorate("indexerConfig", config);
  app.decorate("indexerStore", store);
  app.decorate("realtimeHub", realtimeHub);

  app.register(websocket);

  app.addHook("onReady", async () => {
    await app.indexerStore.initialize();
  });

  app.addHook("onClose", async () => {
    await Promise.all([
      app.realtimeHub.close(),
      app.indexerStore.close()
    ]);
  });

  app.register(healthRoutes);
  app.register(automatonRoutes);
  app.register(realtimeRoutes);
  app.register(spawnSessionRoutes);

  return app;
}

async function start() {
  const app = buildServer();

  try {
    await app.listen({
      host: app.indexerConfig.host,
      port: app.indexerConfig.port
    });
  } catch (error) {
    app.log.error(error);
    process.exitCode = 1;
  }
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  void start();
}

