function formatTime(timestamp: number): string {
  return new Intl.DateTimeFormat("en-GB", {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
    timeZone: "UTC"
  }).format(timestamp);
}

interface MonologuePanelProps {
  entries: readonly MonologueEntry[];
}

export function MonologuePanel({ entries }: MonologuePanelProps) {
  return (
    <section className="log-section" aria-labelledby="monologue-heading">
      <div className="panel-heading">
        <h3 id="monologue-heading">Inner Monologue</h3>
        <span className="panel-note">Realtime shell preview</span>
      </div>

      <div className="log-feed">
        {entries.length > 0 ? (
          entries.map((entry) => (
            <article className="log-line" key={entry.turnId}>
              <span className="log-time">{formatTime(entry.timestamp)}</span>
              <span className={`log-type is-${entry.type}`}>
                {entry.type === "thought" ? "think" : "action"}
              </span>
              <div className="log-copy">
                <p>{entry.message}</p>
                <span>
                  {entry.agentState}
                  {entry.durationMs === null ? "" : ` · ${entry.durationMs}ms`}
                </span>
              </div>
            </article>
          ))
        ) : (
          <p className="empty-copy">
            Monologue entries will stream here once the indexer websocket lands.
          </p>
        )}
      </div>
    </section>
  );
}

